Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, HttpClient client) CreateFetcher(HttpMessageHandler handler)
    {
        var client = new HttpClient(handler);
        return (new DataFetcher(client), client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.InternalServerError,
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange â€” handler that delays forever, so cancellation is the only way out
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage(); // unreachable
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        cts.Cancel();
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledCooperatively()
    {
        // Arrange â€” use TestContext.CancellationToken so [Timeout] triggers cancellation
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage();
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // The [Timeout] attribute fires CancellationToken after 3 s,
        // proving the method respects cooperative cancellation.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    /// <summary>Minimal in-process handler that avoids real HTTP calls.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => Task.FromResult(response)) { }

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance & design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, avoids nullability warnings |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout â€” MSTest cancels the token when time expires |
| `Assert.ThrowsExactlyAsync<T>` | Modern exception assertion (not `[ExpectedException]`) |
| `FakeHandler` (custom `HttpMessageHandler`) | No real HTTP; full control over responses and delays |

The **timeout test** is the most important pattern here â€” by passing `_testContext.CancellationToken` into `FetchAsync`, the `[Timeout(3000)]` attribute will cancel that token after 3 seconds, proving your code cooperates with cancellation instead of hanging.
